const DVZ_LEGACY_SRGB_BLEND: bool = false;
// Shared transform pipeline for builtin scene vertex shaders.
//
// Bind group layout (group 0):
//   binding 0: MVP { model, view, proj, time, flags }
//   binding 1: Viewport { x, y, width, height }

struct MVP {
    model: mat4x4f,
    view: mat4x4f,
    proj: mat4x4f,
    time: f32,
    flags: u32,
}

struct Viewport {
    rect: vec4f,
}

@group(0) @binding(0) var<uniform> mvp: MVP;
@group(0) @binding(1) var<uniform> viewport: Viewport;

fn transform(position: vec3f) -> vec4f {
    return mvp.proj * mvp.view * mvp.model * vec4f(position, 1.0);
}


struct VertexIn {
    @location(0) position: vec3f,
    @location(1) color: vec4f,
    @location(2) size: f32,
}

struct VertexOut {
    @builtin(position) position: vec4f,
    @location(0) color: vec4f,
    @location(1) corner: vec2f,
    @location(2) size: f32,
}

fn quad_corner(vertex_id: u32) -> vec2f {
    let corners = array<vec2f, 6>(
        vec2f(-1.0, -1.0),
        vec2f( 1.0, -1.0),
        vec2f(-1.0,  1.0),
        vec2f(-1.0,  1.0),
        vec2f( 1.0, -1.0),
        vec2f( 1.0,  1.0),
    );
    return corners[vertex_id];
}

@vertex
fn main(@builtin(vertex_index) vertex_id: u32, input: VertexIn) -> VertexOut {
    let corner = quad_corner(vertex_id);
    let center = mvp.proj * mvp.view * mvp.model * vec4f(input.position, 1.0);
    let sprite_size = max(input.size + 4.0, 1.0);
    let radius = vec2f(sprite_size / viewport.rect.z, sprite_size / viewport.rect.w);

    var output: VertexOut;
    output.position = vec4f(center.xy + corner * radius * center.w, center.zw);
    output.color = input.color;
    output.corner = corner;
    output.size = input.size;
    return output;
}

const DVZ_LEGACY_SRGB_BLEND: bool = false;
fn srgb_to_linear(srgb: vec3f) -> vec3f {
    let clipped = clamp(srgb, vec3f(0.0), vec3f(1.0));
    let lo = clipped / vec3f(12.92);
    let hi = pow((clipped + vec3f(0.055)) / vec3f(1.055), vec3f(2.4));
    return select(hi, lo, clipped <= vec3f(0.04045));
}

fn semantic_color_to_linear(color: vec4f) -> vec4f {
    let clipped = clamp(color.rgb, vec3f(0.0), vec3f(1.0));
    if (DVZ_LEGACY_SRGB_BLEND) {
        return vec4f(clipped, clamp(color.a, 0.0, 1.0));
    }
    return vec4f(srgb_to_linear(clipped), clamp(color.a, 0.0, 1.0));
}

fn sampled_texture_color_to_linear(color: vec4f, params: vec4f) -> vec4f {
    if (params.x > 0.5) {
        return semantic_color_to_linear(color);
    }
    return vec4f(color.rgb, clamp(color.a, 0.0, 1.0));
}


struct FragmentIn {
    @location(0) color: vec4f,
    @location(1) corner: vec2f,
    @location(2) size: f32,
}

fn point_disc_distance(corner: vec2f, size: f32) -> f32 {
    let point_size = max(size, 0.0);
    let sprite_size = max(point_size + 4.0, 1.0);
    return length(corner * 0.5 * sprite_size) - 0.5 * point_size;
}

fn point_disc_coverage(dist: f32) -> f32 {
    let aa = max(fwidth(dist), 1e-6);
    return 1.0 - smoothstep(-aa, aa, dist);
}

@fragment
fn main(input: FragmentIn) -> @location(0) vec4f {
    let dist = point_disc_distance(input.corner, input.size);
    let alpha = point_disc_coverage(dist);
    if (alpha <= 0.0) {
        discard;
    }
    let color = semantic_color_to_linear(input.color);
    return vec4f(color.rgb, color.a * alpha);
}

