struct SceneMaterial {
    light_direction: vec4f,
    params: vec4f,
    model: vec4f,
    base_color_factor: vec4f,
    standard_params: vec4f,
    emissive_rim: vec4f,
    limb_params: vec4f,
    depth_cue: vec4f,
    depth_cue_color: vec4f,
    depth_cue_extra: vec4f,
}

@group(1) @binding(0) var<uniform> material: SceneMaterial;

fn evaluate_scene_material_linear_item(
    linear_item_color: vec4f,
    normal: vec3f,
    world_position: vec3f,
    camera_position: vec3f,
) -> vec4f {
    let model = i32(material.model.x + 0.5);
    let opacity = clamp(material.model.y, 0.0, 1.0);
    let linear_base_color = semantic_color_to_linear(material.base_color_factor);
    let emissive = srgb_to_linear(material.emissive_rim.rgb);
    let base = linear_item_color.rgb * linear_base_color.rgb;
    let alpha = linear_item_color.a * linear_base_color.a * opacity;
    if (model == 0) {
        return vec4f(clamp(base + emissive, vec3f(0.0), vec3f(1.0)), alpha);
    }

    let n = normalize(normal);
    let l = normalize(material.light_direction.xyz);
    let v = normalize(camera_position - world_position);
    if (model == 3) {
        let falloff = max(material.limb_params.x, 0.01);
        let sun_bias = material.limb_params.y;
        let terminator_width = max(material.limb_params.z, 1e-4);
        let night_factor = clamp(material.limb_params.w, 0.0, 1.0);
        let facing = clamp(dot(n, v), 0.0, 1.0);
        let peak_facing = 2.0 / (falloff + 2.0);
        let peak = peak_facing * peak_facing * pow(1.0 - peak_facing, falloff);
        let limb = facing * facing * pow(1.0 - facing, falloff) / max(peak, 1e-6);
        let sunlight = smoothstep(
            -terminator_width, terminator_width, dot(n, l) + sun_bias);
        let illumination = mix(night_factor, 1.0, sunlight);
        return vec4f(clamp(base, vec3f(0.0), vec3f(1.0)), alpha * limb * illumination);
    }
    let h = normalize(l + v);
    let lambert = max(dot(n, l), 0.0);
    if (model == 2) {
        let roughness = clamp(material.standard_params.x, 0.0, 1.0);
        let specular_strength = max(material.standard_params.y, 0.0);
        let metallic = clamp(material.standard_params.z, 0.0, 1.0);
        let rim_strength = max(material.standard_params.w, 0.0);
        let shininess = max(1.0, 128.0 * (1.0 - roughness) + 1.0);
        let specular = pow(max(dot(n, h), 0.0), shininess) * specular_strength;
        let rim = pow(1.0 - max(dot(n, v), 0.0), 2.0) * rim_strength;
        let diffuse = base * (0.04 + (1.0 - metallic) * lambert);
        let rgb = diffuse + vec3f(specular + rim) + emissive;
        return vec4f(clamp(rgb, vec3f(0.0), vec3f(1.0)), alpha);
    }

    let specular = pow(max(dot(n, h), 0.0), max(material.params.w, 1.0));
    let rgb = base * (material.params.x + material.params.y * lambert) +
        vec3f(material.params.z * specular);
    return vec4f(clamp(rgb, vec3f(0.0), vec3f(1.0)), alpha);
}

fn evaluate_scene_material(
    item_color: vec4f,
    normal: vec3f,
    world_position: vec3f,
    camera_position: vec3f,
) -> vec4f {
    return evaluate_scene_material_linear_item(
        semantic_color_to_linear(item_color), normal, world_position, camera_position);
}

fn depth_cue_coordinate(cue: vec3f) -> f32 {
    let metric = i32(material.depth_cue_extra.x + 0.5);
    if (metric == 1) {
        return cue.y;
    }
    if (metric == 2) {
        return cue.z;
    }
    return cue.x;
}

fn depth_cue_factor(cue: vec3f) -> f32 {
    let strength = clamp(material.depth_cue.z, 0.0, 1.0);
    let mode = i32(material.depth_cue.w + 0.5);
    if (mode == 0 || strength <= 0.0) {
        return 0.0;
    }

    let denom = max(material.depth_cue.y - material.depth_cue.x, 1e-6);
    let coord = depth_cue_coordinate(cue);
    var t = clamp((coord - material.depth_cue.x) / denom, 0.0, 1.0);
    let falloff = i32(material.depth_cue_extra.y + 0.5);
    if (falloff == 1) {
        let density = max(material.depth_cue_extra.z, 1e-6);
        t = (1.0 - exp(-density * t)) / max(1.0 - exp(-density), 1e-6);
    }
    return t * strength;
}

fn apply_depth_cue(rgb: vec3f, cue: vec3f) -> vec3f {
    let mode = i32(material.depth_cue.w + 0.5);
    let t = depth_cue_factor(cue);
    if (t <= 0.0) {
        return rgb;
    }
    if (mode == 1) {
        return mix(rgb, srgb_to_linear(material.depth_cue_color.rgb), t);
    }
    if (mode == 2) {
        let luma = dot(rgb, vec3f(0.2126, 0.7152, 0.0722));
        return mix(rgb, vec3f(luma), t);
    }
    if (mode == 3) {
        return mix(rgb, vec3f(0.0), t);
    }
    return rgb;
}


struct FragmentIn {
    @location(0) color: vec4f,
    @location(1) sprite: vec2f,
    @location(2) size: f32,
    @location(3) angle: f32,
    @location(4) @interpolate(flat) shape: u32,
}

fn sd_equilateral_triangle(p_in: vec2f) -> f32 {
    let k = 1.7320508;
    var p = vec2f(abs(p_in.x) - 1.0, p_in.y + 1.0 / k);
    if (p.x + k * p.y > 0.0) {
        p = vec2f(p.x - k * p.y, -k * p.x - p.y) * 0.5;
    }
    p.x -= clamp(p.x, -2.0, 0.0);
    return -length(p) * sign(p.y);
}

fn sd_box(p: vec2f, b: vec2f) -> f32 {
    let d = abs(p) - b;
    return length(max(d, vec2f(0.0))) + min(max(d.x, d.y), 0.0);
}

fn sd_round_box(p: vec2f, b: vec2f, r: f32) -> f32 {
    let q = abs(p) - b + vec2f(r);
    return length(max(q, vec2f(0.0))) + min(max(q.x, q.y), 0.0) - r;
}

fn sd_segment(p: vec2f, a: vec2f, b: vec2f) -> f32 {
    let pa = p - a;
    let ba = b - a;
    let h = clamp(dot(pa, ba) / dot(ba, ba), 0.0, 1.0);
    return length(pa - ba * h);
}

fn sd_triangle(p: vec2f) -> f32 {
    let a = vec2f(-1.0, -1.0);
    let b = vec2f(1.0, -1.0);
    let c = vec2f(0.0, 1.0);
    let d = min(sd_segment(p, a, b), min(sd_segment(p, b, c), sd_segment(p, c, a)));
    let s0 = (b.x - a.x) * (p.y - a.y) - (b.y - a.y) * (p.x - a.x);
    let s1 = (c.x - b.x) * (p.y - b.y) - (c.y - b.y) * (p.x - b.x);
    let s2 = (a.x - c.x) * (p.y - c.y) - (a.y - c.y) * (p.x - c.x);
    return select(d, -d, s0 >= 0.0 && s1 >= 0.0 && s2 >= 0.0);
}

fn sd_ellipse(p: vec2f, r: vec2f) -> f32 {
    return (length(p / r) - 1.0) * min(r.x, r.y);
}

fn sd_heart(p_in: vec2f) -> f32 {
    var p = vec2f(p_in.x, -p_in.y) * 0.82 + vec2f(0.0, 0.18);
    p.x = abs(p.x);
    if (p.y + p.x > 1.0) {
        return length(p - vec2f(0.25, 0.75)) - 0.3535534;
    }
    let h = max(p.x + p.y, 0.0);
    let d0 = dot(p - vec2f(0.0, 1.0), p - vec2f(0.0, 1.0));
    let d1 = dot(p - vec2f(0.5 * h), p - vec2f(0.5 * h));
    return sqrt(min(d0, d1)) * sign(p.x - p.y);
}

fn marker_distance(p: vec2f, shape: u32) -> f32 {
    if (shape == 1u) {
        return sd_box(p, vec2f(1.0));
    }
    if (shape == 2u) {
        return sd_triangle(p);
    }
    if (shape == 3u) {
        return abs(p.x) + abs(p.y) - 1.0;
    }
    if (shape == 4u) {
        return min(sd_box(p, vec2f(0.28, 1.0)), sd_box(p, vec2f(1.0, 0.28)));
    }
    if (shape == 5u) {
        return abs(length(p) - 0.62) - 0.18;
    }
    if (shape == 6u) {
        let ring = abs(length(p) - 0.48) - 0.04;
        let h = sd_box(p, vec2f(1.0, 0.028));
        let v = sd_box(p, vec2f(0.028, 1.0));
        let inner = length(p) - 0.24;
        let crosshair = max(min(h, v), -inner);
        return min(ring, crosshair);
    }
    if (shape == 7u) {
        let a = sd_segment(p, vec2f(-0.9, 0.0), vec2f(0.9, 0.0));
        let b = sd_segment(p, vec2f(-0.45, -0.78), vec2f(0.45, 0.78));
        let c = sd_segment(p, vec2f(-0.45, 0.78), vec2f(0.45, -0.78));
        return min(a, min(b, c)) - 0.09;
    }
    if (shape == 8u) {
        let a = sd_segment(p, vec2f(-0.72, 0.58), vec2f(0.0, -0.42));
        let b = sd_segment(p, vec2f(0.0, -0.42), vec2f(0.72, 0.58));
        return min(a, b) - 0.13;
    }
    if (shape == 9u) {
        var d = length(p - vec2f(0.0, 0.46)) - 0.43;
        d = min(d, length(p - vec2f(0.46, 0.0)) - 0.43);
        d = min(d, length(p - vec2f(0.0, -0.46)) - 0.43);
        d = min(d, length(p - vec2f(-0.46, 0.0)) - 0.43);
        return d;
    }
    if (shape == 10u) {
        var d = length(p - vec2f(0.0, 0.36)) - 0.36;
        d = min(d, length(p - vec2f(-0.34, -0.08)) - 0.36);
        d = min(d, length(p - vec2f(0.34, -0.08)) - 0.36);
        d = min(d, sd_box(p - vec2f(0.0, -0.58), vec2f(0.16, 0.38)));
        return d;
    }
    if (shape == 11u) {
        let shaft = sd_box(p - vec2f(-0.28, 0.0), vec2f(0.58, 0.18));
        let head = sd_equilateral_triangle(vec2f(-p.y * 1.35, (p.x - 0.12) * 1.35));
        return min(shaft, head);
    }
    if (shape == 12u) {
        return sd_ellipse(p, vec2f(0.98, 0.56));
    }
    if (shape == 13u) {
        return sd_box(p, vec2f(1.0, 0.28));
    }
    if (shape == 14u) {
        return sd_heart(p);
    }
    if (shape == 15u) {
        let left = abs(length(p - vec2f(-0.42, 0.0)) - 0.35) - 0.12;
        let right = abs(length(p - vec2f(0.42, 0.0)) - 0.35) - 0.12;
        return min(left, right);
    }
    if (shape == 16u) {
        let head = length(p - vec2f(0.0, 0.28)) - 0.5;
        let tip = sd_equilateral_triangle(vec2f(p.x * 1.15, p.y * 1.15 + 0.3));
        let hole = -(length(p - vec2f(0.0, 0.30)) - 0.18);
        return max(min(head, tip), hole);
    }
    if (shape == 17u) {
        var d = sd_heart(vec2f(p.x, -p.y + 0.08));
        d = min(d, sd_box(p - vec2f(0.0, -0.62), vec2f(0.16, 0.34)));
        return d;
    }
    if (shape == 18u) {
        let tag = max(sd_round_box(p - vec2f(0.08, 0.0), vec2f(0.86, 0.58), 0.12), p.x + p.y - 1.0);
        let hole = -(length(p - vec2f(-0.54, 0.0)) - 0.12);
        return max(tag, hole);
    }
    if (shape == 19u) {
        return sd_box(p, vec2f(0.28, 1.0));
    }
    if (shape == 20u) {
        return sd_round_box(p, vec2f(0.96, 0.68), 0.18);
    }
    return length(p) - 1.0;
}

@fragment
fn main(input: FragmentIn) -> @location(0) vec4f {
    let c = cos(input.angle);
    let s = sin(input.angle);
    let marker_coord = input.sprite;
    let p = vec2f(
        c * marker_coord.x + s * marker_coord.y, -s * marker_coord.x + c * marker_coord.y);

    let dist = marker_distance(p, input.shape);
    let aa = max(fwidth(dist), 1e-6);
    let outer = 1.0 - smoothstep(-aa, aa, dist);
    if (outer <= 0.0) {
        discard;
    }

    let line_width = max(material.params.x, 0.0);
    let aspect = i32(material.params.y + 0.5);
    let filled = aspect == 0 || aspect == 2;
    let stroke = aspect == 1 || aspect == 2;
    let stroke_width_px = select(0.0, max(2.0 * max(line_width, 1.0) / max(input.size, 1.0), aa), stroke);
    let edge_mask = select(0.0, 1.0 - smoothstep(stroke_width_px - aa, stroke_width_px + aa, -dist), stroke);
    let fill_mask = select(0.0, 1.0 - edge_mask, filled);
    let stroke_mask = select(0.0, edge_mask, stroke);
    let coverage = outer * max(fill_mask, stroke_mask);
    if (coverage <= 0.0) {
        discard;
    }

    let edge_color = semantic_color_to_linear(material.base_color_factor);
    let input_color = semantic_color_to_linear(input.color);
    let color = select(edge_color, mix(input_color, edge_color, stroke_mask), filled);
    let out_color = vec4f(color.rgb, color.a * coverage);
    if (out_color.a <= 0.0) {
        discard;
    }
    return out_color;
}

const DVZ_LEGACY_SRGB_BLEND: bool = false;
// Shared transform pipeline for builtin scene vertex shaders.
//
// Bind group layout (group 0):
//   binding 0: MVP { model, view, proj, time, flags }
//   binding 1: Viewport { x, y, width, height }

struct MVP {
    model: mat4x4f,
    view: mat4x4f,
    proj: mat4x4f,
    time: f32,
    flags: u32,
}

struct Viewport {
    rect: vec4f,
}

@group(0) @binding(0) var<uniform> mvp: MVP;
@group(0) @binding(1) var<uniform> viewport: Viewport;

fn transform(position: vec3f) -> vec4f {
    return mvp.proj * mvp.view * mvp.model * vec4f(position, 1.0);
}

fn srgb_to_linear(srgb: vec3f) -> vec3f {
    let clipped = clamp(srgb, vec3f(0.0), vec3f(1.0));
    let lo = clipped / vec3f(12.92);
    let hi = pow((clipped + vec3f(0.055)) / vec3f(1.055), vec3f(2.4));
    return select(hi, lo, clipped <= vec3f(0.04045));
}

fn semantic_color_to_linear(color: vec4f) -> vec4f {
    let clipped = clamp(color.rgb, vec3f(0.0), vec3f(1.0));
    if (DVZ_LEGACY_SRGB_BLEND) {
        return vec4f(clipped, clamp(color.a, 0.0, 1.0));
    }
    return vec4f(srgb_to_linear(clipped), clamp(color.a, 0.0, 1.0));
}

fn sampled_texture_color_to_linear(color: vec4f, params: vec4f) -> vec4f {
    if (params.x > 0.5) {
        return semantic_color_to_linear(color);
    }
    return vec4f(color.rgb, clamp(color.a, 0.0, 1.0));
}

struct SceneMaterial {
    light_direction: vec4f,
    params: vec4f,
    model: vec4f,
    base_color_factor: vec4f,
    standard_params: vec4f,
    emissive_rim: vec4f,
    limb_params: vec4f,
    depth_cue: vec4f,
    depth_cue_color: vec4f,
    depth_cue_extra: vec4f,
}

@group(1) @binding(0) var<uniform> material: SceneMaterial;

fn evaluate_scene_material_linear_item(
    linear_item_color: vec4f,
    normal: vec3f,
    world_position: vec3f,
    camera_position: vec3f,
) -> vec4f {
    let model = i32(material.model.x + 0.5);
    let opacity = clamp(material.model.y, 0.0, 1.0);
    let linear_base_color = semantic_color_to_linear(material.base_color_factor);
    let emissive = srgb_to_linear(material.emissive_rim.rgb);
    let base = linear_item_color.rgb * linear_base_color.rgb;
    let alpha = linear_item_color.a * linear_base_color.a * opacity;
    if (model == 0) {
        return vec4f(clamp(base + emissive, vec3f(0.0), vec3f(1.0)), alpha);
    }

    let n = normalize(normal);
    let l = normalize(material.light_direction.xyz);
    let v = normalize(camera_position - world_position);
    if (model == 3) {
        let falloff = max(material.limb_params.x, 0.01);
        let sun_bias = material.limb_params.y;
        let terminator_width = max(material.limb_params.z, 1e-4);
        let night_factor = clamp(material.limb_params.w, 0.0, 1.0);
        let facing = clamp(dot(n, v), 0.0, 1.0);
        let peak_facing = 2.0 / (falloff + 2.0);
        let peak = peak_facing * peak_facing * pow(1.0 - peak_facing, falloff);
        let limb = facing * facing * pow(1.0 - facing, falloff) / max(peak, 1e-6);
        let sunlight = smoothstep(
            -terminator_width, terminator_width, dot(n, l) + sun_bias);
        let illumination = mix(night_factor, 1.0, sunlight);
        return vec4f(clamp(base, vec3f(0.0), vec3f(1.0)), alpha * limb * illumination);
    }
    let h = normalize(l + v);
    let lambert = max(dot(n, l), 0.0);
    if (model == 2) {
        let roughness = clamp(material.standard_params.x, 0.0, 1.0);
        let specular_strength = max(material.standard_params.y, 0.0);
        let metallic = clamp(material.standard_params.z, 0.0, 1.0);
        let rim_strength = max(material.standard_params.w, 0.0);
        let shininess = max(1.0, 128.0 * (1.0 - roughness) + 1.0);
        let specular = pow(max(dot(n, h), 0.0), shininess) * specular_strength;
        let rim = pow(1.0 - max(dot(n, v), 0.0), 2.0) * rim_strength;
        let diffuse = base * (0.04 + (1.0 - metallic) * lambert);
        let rgb = diffuse + vec3f(specular + rim) + emissive;
        return vec4f(clamp(rgb, vec3f(0.0), vec3f(1.0)), alpha);
    }

    let specular = pow(max(dot(n, h), 0.0), max(material.params.w, 1.0));
    let rgb = base * (material.params.x + material.params.y * lambert) +
        vec3f(material.params.z * specular);
    return vec4f(clamp(rgb, vec3f(0.0), vec3f(1.0)), alpha);
}

fn evaluate_scene_material(
    item_color: vec4f,
    normal: vec3f,
    world_position: vec3f,
    camera_position: vec3f,
) -> vec4f {
    return evaluate_scene_material_linear_item(
        semantic_color_to_linear(item_color), normal, world_position, camera_position);
}

fn depth_cue_coordinate(cue: vec3f) -> f32 {
    let metric = i32(material.depth_cue_extra.x + 0.5);
    if (metric == 1) {
        return cue.y;
    }
    if (metric == 2) {
        return cue.z;
    }
    return cue.x;
}

fn depth_cue_factor(cue: vec3f) -> f32 {
    let strength = clamp(material.depth_cue.z, 0.0, 1.0);
    let mode = i32(material.depth_cue.w + 0.5);
    if (mode == 0 || strength <= 0.0) {
        return 0.0;
    }

    let denom = max(material.depth_cue.y - material.depth_cue.x, 1e-6);
    let coord = depth_cue_coordinate(cue);
    var t = clamp((coord - material.depth_cue.x) / denom, 0.0, 1.0);
    let falloff = i32(material.depth_cue_extra.y + 0.5);
    if (falloff == 1) {
        let density = max(material.depth_cue_extra.z, 1e-6);
        t = (1.0 - exp(-density * t)) / max(1.0 - exp(-density), 1e-6);
    }
    return t * strength;
}

fn apply_depth_cue(rgb: vec3f, cue: vec3f) -> vec3f {
    let mode = i32(material.depth_cue.w + 0.5);
    let t = depth_cue_factor(cue);
    if (t <= 0.0) {
        return rgb;
    }
    if (mode == 1) {
        return mix(rgb, srgb_to_linear(material.depth_cue_color.rgb), t);
    }
    if (mode == 2) {
        let luma = dot(rgb, vec3f(0.2126, 0.7152, 0.0722));
        return mix(rgb, vec3f(luma), t);
    }
    if (mode == 3) {
        return mix(rgb, vec3f(0.0), t);
    }
    return rgb;
}


struct VertexIn {
    @location(0) position_start: vec3f,
    @location(1) position_end: vec3f,
    @location(2) color: vec4f,
    @location(3) line_width: f32,
}

struct VertexOut {
    @builtin(position) position: vec4f,
    @location(0) color: vec4f,
    @location(1) coord: vec2f,
    @location(2) length_px: f32,
    @location(3) line_width: f32,
}

const CLIP_EPS: f32 = 1e-5;

fn clip_to_pixel(clip: vec4f) -> vec2f {
    let ndc = clip.xy / max(clip.w, CLIP_EPS);
    return (ndc * 0.5 + vec2f(0.5)) * viewport.rect.zw;
}

fn pixel_to_clip(pixel: vec2f, clip: vec4f) -> vec4f {
    let ndc = pixel / max(viewport.rect.zw, vec2f(1.0)) * 2.0 - vec2f(1.0);
    return vec4f(ndc * clip.w, clip.z, clip.w);
}

fn clip_segment_plane(
    start_clip: ptr<function, vec4f>, end_clip: ptr<function, vec4f>, start_dist: f32,
    end_dist: f32) -> bool {
    if (start_dist < 0.0 && end_dist < 0.0) {
        return false;
    }
    if (start_dist < 0.0 || end_dist < 0.0) {
        let t = start_dist / (start_dist - end_dist);
        let clipped = mix(*start_clip, *end_clip, clamp(t, 0.0, 1.0));
        if (start_dist < 0.0) {
            *start_clip = clipped;
        } else {
            *end_clip = clipped;
        }
    }
    return true;
}

fn clip_segment_to_view(start_clip: ptr<function, vec4f>, end_clip: ptr<function, vec4f>) -> bool {
    if (!clip_segment_plane(
        start_clip, end_clip, (*start_clip).w - CLIP_EPS, (*end_clip).w - CLIP_EPS)) {
        return false;
    }
    if (!clip_segment_plane(
        start_clip, end_clip, (*start_clip).x + (*start_clip).w,
        (*end_clip).x + (*end_clip).w)) {
        return false;
    }
    if (!clip_segment_plane(
        start_clip, end_clip, (*start_clip).w - (*start_clip).x,
        (*end_clip).w - (*end_clip).x)) {
        return false;
    }
    if (!clip_segment_plane(
        start_clip, end_clip, (*start_clip).y + (*start_clip).w,
        (*end_clip).y + (*end_clip).w)) {
        return false;
    }
    if (!clip_segment_plane(
        start_clip, end_clip, (*start_clip).w - (*start_clip).y,
        (*end_clip).w - (*end_clip).y)) {
        return false;
    }
    if (!clip_segment_plane(start_clip, end_clip, (*start_clip).z, (*end_clip).z)) {
        return false;
    }
    return clip_segment_plane(
        start_clip, end_clip, (*start_clip).w - (*start_clip).z,
        (*end_clip).w - (*end_clip).z);
}

fn stroke_outer_half_width(line_width: f32) -> f32 {
    return max(line_width, 0.0) * 0.5 + 1.5;
}

fn stroke_triangle_head_length(line_width: f32) -> f32 {
    return max(max(line_width, 0.0) * 3.0, stroke_outer_half_width(line_width));
}

fn stroke_triangle_head_half_width(line_width: f32) -> f32 {
    return max(max(line_width, 0.0) * 1.5, stroke_outer_half_width(line_width));
}

fn stroke_cap_extension(cap: i32, line_width: f32) -> f32 {
    if (cap == 0 || cap == 5) {
        return 0.0;
    }
    if (cap == 3) {
        return stroke_triangle_head_length(line_width) + 1.0;
    }
    return stroke_outer_half_width(line_width);
}

fn stroke_cap_half_width(cap: i32, line_width: f32) -> f32 {
    if (cap == 3) {
        return stroke_triangle_head_half_width(line_width) + 1.0;
    }
    return stroke_outer_half_width(line_width);
}

@vertex
fn main(@builtin(vertex_index) vertex_index: u32, input: VertexIn) -> VertexOut {
    var start_clip = transform(input.position_start);
    var end_clip = transform(input.position_end);
    if (!clip_segment_to_view(&start_clip, &end_clip)) {
        var output: VertexOut;
        output.position = vec4f(2.0, 2.0, 1.0, 1.0);
        output.color = vec4f(0.0);
        output.coord = vec2f(0.0);
        output.length_px = 0.0;
        output.line_width = 0.0;
        return output;
    }

    let start_px = clip_to_pixel(start_clip);
    let end_px = clip_to_pixel(end_clip);

    var tangent = end_px - start_px;
    let length_px = length(tangent);
    if (length_px <= 1e-6) {
        tangent = vec2f(1.0, 0.0);
    } else {
        tangent = tangent / length_px;
    }
    let normal = vec2f(-tangent.y, tangent.x);

    let line_width = max(input.line_width, 0.0);
    let start_cap = i32(material.params.x + 0.5);
    let end_cap = i32(material.params.y + 0.5);
    let start_extension = stroke_cap_extension(start_cap, line_width);
    let end_extension = stroke_cap_extension(end_cap, line_width);
    let start_half_width = stroke_cap_half_width(start_cap, line_width);
    let end_half_width = stroke_cap_half_width(end_cap, line_width);
    let vertex = vertex_index & 3u;

    var pixel = start_px;
    var clip = start_clip;
    var coord = vec2f(0.0);

    if (vertex == 0u) {
        pixel = start_px - tangent * start_extension + normal * start_half_width;
        coord = vec2f(-start_extension, start_half_width);
    } else if (vertex == 1u) {
        pixel = start_px - tangent * start_extension - normal * start_half_width;
        coord = vec2f(-start_extension, -start_half_width);
    } else if (vertex == 2u) {
        pixel = end_px + tangent * end_extension - normal * end_half_width;
        coord = vec2f(length_px + end_extension, -end_half_width);
        clip = end_clip;
    } else {
        pixel = end_px + tangent * end_extension + normal * end_half_width;
        coord = vec2f(length_px + end_extension, end_half_width);
        clip = end_clip;
    }

    var output: VertexOut;
    output.position = pixel_to_clip(pixel, clip);
    output.color = input.color;
    output.coord = coord;
    output.length_px = length_px;
    output.line_width = line_width;
    return output;
}

