struct FragmentIn {
    @location(0) color: vec4f,
    @location(1) coord: vec2f,
    @location(2) length_px: f32,
    @location(3) line_width: f32,
}

fn stroke_alpha(distance: f32, line_width: f32) -> f32 {
    let aa = 1.0;
    let half_width = max(line_width, 0.0) * 0.5;
    return 1.0 - smoothstep(half_width - aa, half_width + aa, abs(distance));
}

fn stroke_outer_half_width(line_width: f32) -> f32 {
    return max(line_width, 0.0) * 0.5 + 1.5;
}

fn stroke_triangle_head_length(line_width: f32) -> f32 {
    return max(max(line_width, 0.0) * 3.0, stroke_outer_half_width(line_width));
}

fn stroke_triangle_head_half_width(line_width: f32) -> f32 {
    return max(max(line_width, 0.0) * 1.5, stroke_outer_half_width(line_width));
}

fn stroke_cap_distance(cap: i32, dx: f32, dy: f32, line_width: f32) -> f32 {
    let aa = 1.0;
    let half_width = max(line_width, 0.0) * 0.5;
    let t = max(half_width - aa, 0.0);
    let x = abs(dx);
    let y = abs(dy);

    if (cap == 0) {
        return 1e6;
    }
    if (cap == 1) {
        return length(vec2f(x, y));
    }
    if (cap == 2) {
        return max(y, t + x - y);
    }
    if (cap == 4) {
        return max(x, y);
    }
    return max(x + t, y);
}

fn stroke_triangle_out_alpha(dx: f32, dy: f32, line_width: f32) -> f32 {
    let aa = 1.0;
    let x = max(dx, 0.0);
    let y = abs(dy);
    let length_px = stroke_triangle_head_length(line_width);
    let half_width = stroke_triangle_head_half_width(line_width);
    let scale = min(length_px, half_width);
    let edge_distance = (x / max(length_px, 1e-6) + y / max(half_width, 1e-6) - 1.0) * scale;
    let tip_distance = x - length_px;
    let distance = max(edge_distance, tip_distance);
    return 1.0 - smoothstep(-aa, aa, distance);
}

fn stroke_cap_alpha(cap: i32, dx: f32, dy: f32, line_width: f32) -> f32 {
    if (cap == 3) {
        return stroke_triangle_out_alpha(dx, dy, line_width);
    }
    return stroke_alpha(stroke_cap_distance(cap, dx, dy, line_width), line_width);
}

@fragment
fn main(input: FragmentIn) -> @location(0) vec4f {
    var alpha = stroke_alpha(input.coord.y, input.line_width);
    if (input.coord.x < 0.0) {
        alpha = stroke_cap_alpha(
            i32(material.params.x + 0.5), -input.coord.x, input.coord.y, input.line_width);
    } else if (input.coord.x > input.length_px) {
        alpha = stroke_cap_alpha(
            i32(material.params.y + 0.5), input.coord.x - input.length_px, input.coord.y,
            input.line_width);
    }

    if (alpha <= 0.0) {
        discard;
    }
    let linear_color = semantic_color_to_linear(input.color);
    let color = vec4f(linear_color.rgb, linear_color.a * alpha);
    if (color.a <= 0.0) {
        discard;
    }
    return color;
}

const DVZ_LEGACY_SRGB_BLEND: bool = false;
// Shared transform pipeline for builtin scene vertex shaders.
//
// Bind group layout (group 0):
//   binding 0: MVP { model, view, proj, time, flags }
//   binding 1: Viewport { x, y, width, height }

struct MVP {
    model: mat4x4f,
    view: mat4x4f,
    proj: mat4x4f,
    time: f32,
    flags: u32,
}

struct Viewport {
    rect: vec4f,
}

@group(0) @binding(0) var<uniform> mvp: MVP;
@group(0) @binding(1) var<uniform> viewport: Viewport;

fn transform(position: vec3f) -> vec4f {
    return mvp.proj * mvp.view * mvp.model * vec4f(position, 1.0);
}

fn srgb_to_linear(srgb: vec3f) -> vec3f {
    let clipped = clamp(srgb, vec3f(0.0), vec3f(1.0));
    let lo = clipped / vec3f(12.92);
    let hi = pow((clipped + vec3f(0.055)) / vec3f(1.055), vec3f(2.4));
    return select(hi, lo, clipped <= vec3f(0.04045));
}

fn semantic_color_to_linear(color: vec4f) -> vec4f {
    let clipped = clamp(color.rgb, vec3f(0.0), vec3f(1.0));
    if (DVZ_LEGACY_SRGB_BLEND) {
        return vec4f(clipped, clamp(color.a, 0.0, 1.0));
    }
    return vec4f(srgb_to_linear(clipped), clamp(color.a, 0.0, 1.0));
}

fn sampled_texture_color_to_linear(color: vec4f, params: vec4f) -> vec4f {
    if (params.x > 0.5) {
        return semantic_color_to_linear(color);
    }
    return vec4f(color.rgb, clamp(color.a, 0.0, 1.0));
}

struct SceneMaterial {
    light_direction: vec4f,
    params: vec4f,
    model: vec4f,
    base_color_factor: vec4f,
    standard_params: vec4f,
    emissive_rim: vec4f,
    limb_params: vec4f,
    depth_cue: vec4f,
    depth_cue_color: vec4f,
    depth_cue_extra: vec4f,
}

@group(1) @binding(0) var<uniform> material: SceneMaterial;

fn evaluate_scene_material_linear_item(
    linear_item_color: vec4f,
    normal: vec3f,
    world_position: vec3f,
    camera_position: vec3f,
) -> vec4f {
    let model = i32(material.model.x + 0.5);
    let opacity = clamp(material.model.y, 0.0, 1.0);
    let linear_base_color = semantic_color_to_linear(material.base_color_factor);
    let emissive = srgb_to_linear(material.emissive_rim.rgb);
    let base = linear_item_color.rgb * linear_base_color.rgb;
    let alpha = linear_item_color.a * linear_base_color.a * opacity;
    if (model == 0) {
        return vec4f(clamp(base + emissive, vec3f(0.0), vec3f(1.0)), alpha);
    }

    let n = normalize(normal);
    let l = normalize(material.light_direction.xyz);
    let v = normalize(camera_position - world_position);
    if (model == 3) {
        let falloff = max(material.limb_params.x, 0.01);
        let sun_bias = material.limb_params.y;
        let terminator_width = max(material.limb_params.z, 1e-4);
        let night_factor = clamp(material.limb_params.w, 0.0, 1.0);
        let facing = clamp(dot(n, v), 0.0, 1.0);
        let peak_facing = 2.0 / (falloff + 2.0);
        let peak = peak_facing * peak_facing * pow(1.0 - peak_facing, falloff);
        let limb = facing * facing * pow(1.0 - facing, falloff) / max(peak, 1e-6);
        let sunlight = smoothstep(
            -terminator_width, terminator_width, dot(n, l) + sun_bias);
        let illumination = mix(night_factor, 1.0, sunlight);
        return vec4f(clamp(base, vec3f(0.0), vec3f(1.0)), alpha * limb * illumination);
    }
    let h = normalize(l + v);
    let lambert = max(dot(n, l), 0.0);
    if (model == 2) {
        let roughness = clamp(material.standard_params.x, 0.0, 1.0);
        let specular_strength = max(material.standard_params.y, 0.0);
        let metallic = clamp(material.standard_params.z, 0.0, 1.0);
        let rim_strength = max(material.standard_params.w, 0.0);
        let shininess = max(1.0, 128.0 * (1.0 - roughness) + 1.0);
        let specular = pow(max(dot(n, h), 0.0), shininess) * specular_strength;
        let rim = pow(1.0 - max(dot(n, v), 0.0), 2.0) * rim_strength;
        let diffuse = base * (0.04 + (1.0 - metallic) * lambert);
        let rgb = diffuse + vec3f(specular + rim) + emissive;
        return vec4f(clamp(rgb, vec3f(0.0), vec3f(1.0)), alpha);
    }

    let specular = pow(max(dot(n, h), 0.0), max(material.params.w, 1.0));
    let rgb = base * (material.params.x + material.params.y * lambert) +
        vec3f(material.params.z * specular);
    return vec4f(clamp(rgb, vec3f(0.0), vec3f(1.0)), alpha);
}

fn evaluate_scene_material(
    item_color: vec4f,
    normal: vec3f,
    world_position: vec3f,
    camera_position: vec3f,
) -> vec4f {
    return evaluate_scene_material_linear_item(
        semantic_color_to_linear(item_color), normal, world_position, camera_position);
}

fn depth_cue_coordinate(cue: vec3f) -> f32 {
    let metric = i32(material.depth_cue_extra.x + 0.5);
    if (metric == 1) {
        return cue.y;
    }
    if (metric == 2) {
        return cue.z;
    }
    return cue.x;
}

fn depth_cue_factor(cue: vec3f) -> f32 {
    let strength = clamp(material.depth_cue.z, 0.0, 1.0);
    let mode = i32(material.depth_cue.w + 0.5);
    if (mode == 0 || strength <= 0.0) {
        return 0.0;
    }

    let denom = max(material.depth_cue.y - material.depth_cue.x, 1e-6);
    let coord = depth_cue_coordinate(cue);
    var t = clamp((coord - material.depth_cue.x) / denom, 0.0, 1.0);
    let falloff = i32(material.depth_cue_extra.y + 0.5);
    if (falloff == 1) {
        let density = max(material.depth_cue_extra.z, 1e-6);
        t = (1.0 - exp(-density * t)) / max(1.0 - exp(-density), 1e-6);
    }
    return t * strength;
}

fn apply_depth_cue(rgb: vec3f, cue: vec3f) -> vec3f {
    let mode = i32(material.depth_cue.w + 0.5);
    let t = depth_cue_factor(cue);
    if (t <= 0.0) {
        return rgb;
    }
    if (mode == 1) {
        return mix(rgb, srgb_to_linear(material.depth_cue_color.rgb), t);
    }
    if (mode == 2) {
        let luma = dot(rgb, vec3f(0.2126, 0.7152, 0.0722));
        return mix(rgb, vec3f(luma), t);
    }
    if (mode == 3) {
        return mix(rgb, vec3f(0.0), t);
    }
    return rgb;
}


struct VertexIn {
    @location(0) position_prev: vec3f,
    @location(1) position_start: vec3f,
    @location(2) position_end: vec3f,
    @location(3) position_next: vec3f,
    @location(4) color: vec4f,
    @location(5) line_width: f32,
    @location(6) path_flags: u32,
    @location(7) path_distance: f32,
}

struct VertexOut {
    @builtin(position) position: vec4f,
    @location(0) color: vec4f,
    @location(1) coord: vec2f,
    @location(2) length_px: f32,
    @location(3) line_width: f32,
    @location(4) has_prev: f32,
    @location(5) has_next: f32,
    @location(6) bevel_distance: vec2f,
    @location(7) join_split_distance: f32,
}

const SIDE_NEGATIVE: u32 = 0x01u;
const ENDPOINT_END: u32 = 0x02u;
const HAS_PREV: u32 = 0x04u;
const HAS_NEXT: u32 = 0x08u;

fn clip_to_pixel(clip: vec4f) -> vec2f {
    let ndc = clip.xy / max(abs(clip.w), 1e-6);
    return (ndc * 0.5 + vec2f(0.5)) * viewport.rect.zw;
}

fn pixel_to_clip(pixel: vec2f, depth: f32) -> vec4f {
    let ndc = pixel / max(viewport.rect.zw, vec2f(1.0)) * 2.0 - vec2f(1.0);
    return vec4f(ndc, depth, 1.0);
}

fn safe_normalize(v: vec2f, fallback: vec2f) -> vec2f {
    let n = length(v);
    if (n <= 1e-6) {
        return fallback;
    }
    return v / n;
}

fn line_distance(p0: vec2f, p1: vec2f, p: vec2f) -> f32 {
    let v = p1 - p0;
    let l2 = max(dot(v, v), 1e-6);
    let u = dot(p - p0, v) / l2;
    let h = p0 + u * v;
    return length(p - h);
}

fn compute_u(p0: vec2f, p1: vec2f, p: vec2f) -> f32 {
    let v = p1 - p0;
    let l = max(length(v), 1e-6);
    return dot(p - p0, v) / l;
}

fn stroke_outer_half_width(line_width: f32) -> f32 {
    return max(line_width, 0.0) * 0.5 + 1.5;
}

fn stroke_triangle_head_length(line_width: f32) -> f32 {
    return max(max(line_width, 0.0) * 3.0, stroke_outer_half_width(line_width));
}

fn stroke_triangle_head_half_width(line_width: f32) -> f32 {
    return max(max(line_width, 0.0) * 1.5, stroke_outer_half_width(line_width));
}

fn stroke_cap_extension(cap: i32, line_width: f32) -> f32 {
    if (cap == 0 || cap == 5) {
        return 0.0;
    }
    if (cap == 3) {
        return stroke_triangle_head_length(line_width) + 1.0;
    }
    return stroke_outer_half_width(line_width);
}

fn stroke_cap_half_width(cap: i32, line_width: f32) -> f32 {
    if (cap == 3) {
        return stroke_triangle_head_half_width(line_width) + 1.0;
    }
    return stroke_outer_half_width(line_width);
}

@vertex
fn main(input: VertexIn) -> VertexOut {
    let side_negative = (input.path_flags & SIDE_NEGATIVE) != 0u;
    let endpoint_end = (input.path_flags & ENDPOINT_END) != 0u;
    let has_prev = (input.path_flags & HAS_PREV) != 0u;
    let has_next = (input.path_flags & HAS_NEXT) != 0u;
    let side = select(1.0, -1.0, side_negative);

    let p0_clip = transform(input.position_prev);
    let p1_clip = transform(input.position_start);
    let p2_clip = transform(input.position_end);
    let p3_clip = transform(input.position_next);
    let p0 = clip_to_pixel(p0_clip);
    let p1 = clip_to_pixel(p1_clip);
    let p2 = clip_to_pixel(p2_clip);
    let p3 = clip_to_pixel(p3_clip);

    var v0 = safe_normalize(p1 - p0, vec2f(1.0, 0.0));
    let v1 = safe_normalize(p2 - p1, v0);
    var v2 = safe_normalize(p3 - p2, v1);
    if (!has_prev) {
        v0 = v1;
    }
    if (!has_next) {
        v2 = v1;
    }
    let n0 = vec2f(-v0.y, v0.x);
    let n1 = vec2f(-v1.y, v1.x);
    let n2 = vec2f(-v2.y, v2.x);

    let stroke_width_px = max(input.line_width, 0.0);
    let half_width = stroke_outer_half_width(stroke_width_px);
    let join_type = i32(material.params.z + 0.5);
    let miter_limit = max(material.params.w, 1.0);
    let length_px = length(p2 - p1);
    let miter_start = safe_normalize(n0 + n1, n1);
    let miter_end = safe_normalize(n1 + n2, n1);
    let denom_start = dot(miter_start, n1);
    let denom_end = dot(miter_end, n1);
    var length_start = select(half_width, half_width / denom_start, denom_start > 1e-3);
    var length_end = select(half_width, half_width / denom_end, denom_end > 1e-3);
    if (join_type == 0) {
        let miter_length_limit = max(miter_limit * (stroke_width_px * 0.5) + 2.0, half_width);
        length_start = min(length_start, miter_length_limit);
        length_end = min(length_end, miter_length_limit);
    } else if (join_type == 2) {
        let bevel_length_limit = max(2.25 * half_width, half_width + 2.0);
        length_start = min(length_start, bevel_length_limit);
        length_end = min(length_end, bevel_length_limit);
    }

    let cap_type = select(i32(material.params.x + 0.5), i32(material.params.y + 0.5), endpoint_end);
    var output: VertexOut;
    var pixel = p1;
    if (!endpoint_end) {
        if (!has_prev) {
            let cap_extension = stroke_cap_extension(cap_type, stroke_width_px);
            let cap_half_width = stroke_cap_half_width(cap_type, stroke_width_px);
            pixel = p1 - cap_extension * v1 + side * cap_half_width * n1;
            output.coord = vec2f(-cap_extension, side * cap_half_width);
        } else {
            pixel = p1 + side * length_start * miter_start;
            output.coord = vec2f(compute_u(p1, p2, pixel), side * half_width);
        }
    } else {
        if (!has_next) {
            let cap_extension = stroke_cap_extension(cap_type, stroke_width_px);
            let cap_half_width = stroke_cap_half_width(cap_type, stroke_width_px);
            pixel = p2 + cap_extension * v1 + side * cap_half_width * n1;
            output.coord = vec2f(length_px + cap_extension, side * cap_half_width);
        } else {
            pixel = p2 + side * length_end * miter_end;
            output.coord = vec2f(compute_u(p1, p2, pixel), side * half_width);
        }
    }
    let depth = select(
        p1_clip.z / max(abs(p1_clip.w), 1e-6),
        p2_clip.z / max(abs(p2_clip.w), 1e-6),
        endpoint_end);
    output.position = pixel_to_clip(pixel, depth);
    output.color = input.color;
    output.bevel_distance = vec2f(-half_width, -half_width);
    output.join_split_distance = 0.0;
    let turn_start = v0.x * v1.y - v0.y * v1.x;
    let turn_end = v1.x * v2.y - v1.y * v2.x;
    let d0 = select(1.0, -1.0, turn_start > 0.0);
    let d1 = select(1.0, -1.0, turn_end > 0.0);
    let start_distance = line_distance(p1 + d0 * n0 * half_width, p1 + d0 * n1 * half_width, pixel);
    let end_distance = line_distance(p2 + d1 * n1 * half_width, p2 + d1 * n2 * half_width, pixel);
    output.bevel_distance.x = select(-start_distance, select(side * d0 * start_distance, -start_distance, endpoint_end), has_prev);
    output.bevel_distance.y = select(-end_distance, select(-end_distance, -side * d1 * end_distance, endpoint_end), has_next);
    output.length_px = length_px;
    output.line_width = stroke_width_px;
    output.has_prev = select(0.0, 1.0, has_prev);
    output.has_next = select(0.0, 1.0, has_next);
    return output;
}

const DVZ_LEGACY_SRGB_BLEND: bool = false;
fn srgb_to_linear(srgb: vec3f) -> vec3f {
    let clipped = clamp(srgb, vec3f(0.0), vec3f(1.0));
    let lo = clipped / vec3f(12.92);
    let hi = pow((clipped + vec3f(0.055)) / vec3f(1.055), vec3f(2.4));
    return select(hi, lo, clipped <= vec3f(0.04045));
}

fn semantic_color_to_linear(color: vec4f) -> vec4f {
    let clipped = clamp(color.rgb, vec3f(0.0), vec3f(1.0));
    if (DVZ_LEGACY_SRGB_BLEND) {
        return vec4f(clipped, clamp(color.a, 0.0, 1.0));
    }
    return vec4f(srgb_to_linear(clipped), clamp(color.a, 0.0, 1.0));
}

fn sampled_texture_color_to_linear(color: vec4f, params: vec4f) -> vec4f {
    if (params.x > 0.5) {
        return semantic_color_to_linear(color);
    }
    return vec4f(color.rgb, clamp(color.a, 0.0, 1.0));
}

struct SceneMaterial {
    light_direction: vec4f,
    params: vec4f,
    model: vec4f,
    base_color_factor: vec4f,
    standard_params: vec4f,
    emissive_rim: vec4f,
    limb_params: vec4f,
    depth_cue: vec4f,
    depth_cue_color: vec4f,
    depth_cue_extra: vec4f,
}

@group(1) @binding(0) var<uniform> material: SceneMaterial;

fn evaluate_scene_material_linear_item(
    linear_item_color: vec4f,
    normal: vec3f,
    world_position: vec3f,
    camera_position: vec3f,
) -> vec4f {
    let model = i32(material.model.x + 0.5);
    let opacity = clamp(material.model.y, 0.0, 1.0);
    let linear_base_color = semantic_color_to_linear(material.base_color_factor);
    let emissive = srgb_to_linear(material.emissive_rim.rgb);
    let base = linear_item_color.rgb * linear_base_color.rgb;
    let alpha = linear_item_color.a * linear_base_color.a * opacity;
    if (model == 0) {
        return vec4f(clamp(base + emissive, vec3f(0.0), vec3f(1.0)), alpha);
    }

    let n = normalize(normal);
    let l = normalize(material.light_direction.xyz);
    let v = normalize(camera_position - world_position);
    if (model == 3) {
        let falloff = max(material.limb_params.x, 0.01);
        let sun_bias = material.limb_params.y;
        let terminator_width = max(material.limb_params.z, 1e-4);
        let night_factor = clamp(material.limb_params.w, 0.0, 1.0);
        let facing = clamp(dot(n, v), 0.0, 1.0);
        let peak_facing = 2.0 / (falloff + 2.0);
        let peak = peak_facing * peak_facing * pow(1.0 - peak_facing, falloff);
        let limb = facing * facing * pow(1.0 - facing, falloff) / max(peak, 1e-6);
        let sunlight = smoothstep(
            -terminator_width, terminator_width, dot(n, l) + sun_bias);
        let illumination = mix(night_factor, 1.0, sunlight);
        return vec4f(clamp(base, vec3f(0.0), vec3f(1.0)), alpha * limb * illumination);
    }
    let h = normalize(l + v);
    let lambert = max(dot(n, l), 0.0);
    if (model == 2) {
        let roughness = clamp(material.standard_params.x, 0.0, 1.0);
        let specular_strength = max(material.standard_params.y, 0.0);
        let metallic = clamp(material.standard_params.z, 0.0, 1.0);
        let rim_strength = max(material.standard_params.w, 0.0);
        let shininess = max(1.0, 128.0 * (1.0 - roughness) + 1.0);
        let specular = pow(max(dot(n, h), 0.0), shininess) * specular_strength;
        let rim = pow(1.0 - max(dot(n, v), 0.0), 2.0) * rim_strength;
        let diffuse = base * (0.04 + (1.0 - metallic) * lambert);
        let rgb = diffuse + vec3f(specular + rim) + emissive;
        return vec4f(clamp(rgb, vec3f(0.0), vec3f(1.0)), alpha);
    }

    let specular = pow(max(dot(n, h), 0.0), max(material.params.w, 1.0));
    let rgb = base * (material.params.x + material.params.y * lambert) +
        vec3f(material.params.z * specular);
    return vec4f(clamp(rgb, vec3f(0.0), vec3f(1.0)), alpha);
}

fn evaluate_scene_material(
    item_color: vec4f,
    normal: vec3f,
    world_position: vec3f,
    camera_position: vec3f,
) -> vec4f {
    return evaluate_scene_material_linear_item(
        semantic_color_to_linear(item_color), normal, world_position, camera_position);
}

fn depth_cue_coordinate(cue: vec3f) -> f32 {
    let metric = i32(material.depth_cue_extra.x + 0.5);
    if (metric == 1) {
        return cue.y;
    }
    if (metric == 2) {
        return cue.z;
    }
    return cue.x;
}

fn depth_cue_factor(cue: vec3f) -> f32 {
    let strength = clamp(material.depth_cue.z, 0.0, 1.0);
    let mode = i32(material.depth_cue.w + 0.5);
    if (mode == 0 || strength <= 0.0) {
        return 0.0;
    }

    let denom = max(material.depth_cue.y - material.depth_cue.x, 1e-6);
    let coord = depth_cue_coordinate(cue);
    var t = clamp((coord - material.depth_cue.x) / denom, 0.0, 1.0);
    let falloff = i32(material.depth_cue_extra.y + 0.5);
    if (falloff == 1) {
        let density = max(material.depth_cue_extra.z, 1e-6);
        t = (1.0 - exp(-density * t)) / max(1.0 - exp(-density), 1e-6);
    }
    return t * strength;
}

fn apply_depth_cue(rgb: vec3f, cue: vec3f) -> vec3f {
    let mode = i32(material.depth_cue.w + 0.5);
    let t = depth_cue_factor(cue);
    if (t <= 0.0) {
        return rgb;
    }
    if (mode == 1) {
        return mix(rgb, srgb_to_linear(material.depth_cue_color.rgb), t);
    }
    if (mode == 2) {
        let luma = dot(rgb, vec3f(0.2126, 0.7152, 0.0722));
        return mix(rgb, vec3f(luma), t);
    }
    if (mode == 3) {
        return mix(rgb, vec3f(0.0), t);
    }
    return rgb;
}


struct FragmentIn {
    @location(0) color: vec4f,
    @location(1) coord: vec2f,
    @location(2) length_px: f32,
    @location(3) line_width: f32,
    @location(4) has_prev: f32,
    @location(5) has_next: f32,
    @location(6) bevel_distance: vec2f,
    @location(7) join_split_distance: f32,
}

fn stroke_alpha(distance: f32, line_width: f32) -> f32 {
    let aa = 1.0;
    let half_width = max(line_width, 0.0) * 0.5;
    return 1.0 - smoothstep(half_width - aa, half_width + aa, abs(distance));
}

fn stroke_outer_half_width(line_width: f32) -> f32 {
    return max(line_width, 0.0) * 0.5 + 1.5;
}

fn stroke_triangle_head_length(line_width: f32) -> f32 {
    return max(max(line_width, 0.0) * 3.0, stroke_outer_half_width(line_width));
}

fn stroke_triangle_head_half_width(line_width: f32) -> f32 {
    return max(max(line_width, 0.0) * 1.5, stroke_outer_half_width(line_width));
}

fn stroke_cap_distance(cap: i32, dx: f32, dy: f32, line_width: f32) -> f32 {
    let aa = 1.0;
    let half_width = max(line_width, 0.0) * 0.5;
    let t = max(half_width - aa, 0.0);
    let x = abs(dx);
    let y = abs(dy);

    if (cap == 0) {
        return 1e6;
    }
    if (cap == 1) {
        return length(vec2f(x, y));
    }
    if (cap == 2) {
        return max(y, t + x - y);
    }
    if (cap == 4) {
        return max(x, y);
    }
    return max(x + t, y);
}

fn stroke_triangle_out_alpha(dx: f32, dy: f32, line_width: f32) -> f32 {
    let aa = 1.0;
    let x = max(dx, 0.0);
    let y = abs(dy);
    let length_px = stroke_triangle_head_length(line_width);
    let half_width = stroke_triangle_head_half_width(line_width);
    let scale = min(length_px, half_width);
    let edge_distance = (x / max(length_px, 1e-6) + y / max(half_width, 1e-6) - 1.0) * scale;
    let tip_distance = x - length_px;
    let distance = max(edge_distance, tip_distance);
    return 1.0 - smoothstep(-aa, aa, distance);
}

fn stroke_cap_alpha(cap: i32, dx: f32, dy: f32, line_width: f32) -> f32 {
    if (cap == 3) {
        return stroke_triangle_out_alpha(dx, dy, line_width);
    }
    return stroke_alpha(stroke_cap_distance(cap, dx, dy, line_width), line_width);
}

@fragment
fn main(input: FragmentIn) -> @location(0) vec4f {
    var distance = input.coord.y;
    var alpha = stroke_alpha(distance, input.line_width);
    let join_type = i32(material.params.z + 0.5);
    let aa = 1.0;
    if (input.coord.x < 0.0) {
        if (input.has_prev >= 0.5 && join_type == 1) {
            distance = length(input.coord);
            alpha = stroke_alpha(distance, input.line_width);
        } else if (input.has_prev < 0.5) {
            let cap_type = i32(material.params.x + 0.5);
            alpha = stroke_cap_alpha(cap_type, -input.coord.x, input.coord.y, input.line_width);
            distance = stroke_cap_distance(cap_type, input.coord.x, input.coord.y, input.line_width);
        }
    } else if (input.coord.x > input.length_px) {
        if (input.has_next >= 0.5 && join_type == 1) {
            distance = length(input.coord - vec2f(input.length_px, 0.0));
            alpha = stroke_alpha(distance, input.line_width);
        } else if (input.has_next < 0.5) {
            let cap_type = i32(material.params.y + 0.5);
            alpha = stroke_cap_alpha(
                cap_type, input.coord.x - input.length_px, input.coord.y, input.line_width);
            distance = stroke_cap_distance(
                cap_type, input.coord.x - input.length_px, input.coord.y, input.line_width);
        }
    }

    let miter_limit = max(material.params.w, 1.0);
    let miter_clip = (miter_limit - 1.0) * (input.line_width * 0.5) + aa;
    let bevel_clip = aa;
    let start_bevel = join_type == 2 && input.coord.x < 0.0 && input.has_prev >= 0.5;
    let end_bevel = join_type == 2 && input.coord.x > input.length_px && input.has_next >= 0.5;
    if (start_bevel) {
        if (input.bevel_distance.x > abs(distance) + bevel_clip) {
            distance = input.bevel_distance.x - bevel_clip;
        }
        alpha = stroke_alpha(distance, input.line_width);
    } else if (end_bevel) {
        if (input.bevel_distance.y > abs(distance) + bevel_clip) {
            distance = input.bevel_distance.y - bevel_clip;
        }
        alpha = stroke_alpha(distance, input.line_width);
    } else if (input.coord.x < 0.0 && input.has_prev >= 0.5 && join_type == 0) {
        if (input.bevel_distance.x > abs(distance) + miter_clip) {
            distance = input.bevel_distance.x - miter_clip;
        }
        alpha = stroke_alpha(distance, input.line_width);
    } else if (input.coord.x > input.length_px && input.has_next >= 0.5 && join_type == 0) {
        if (input.bevel_distance.y > abs(distance) + miter_clip) {
            distance = input.bevel_distance.y - miter_clip;
        }
        alpha = stroke_alpha(distance, input.line_width);
    }
    if (alpha <= 0.0) {
        discard;
    }
    let linear_color = semantic_color_to_linear(input.color);
    let color = vec4f(linear_color.rgb, linear_color.a * alpha);
    if (color.a <= 0.0) {
        discard;
    }
    return color;
}

